<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; background: #f4f6f9; color: #222; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.6rem; }
  h2 { font-size: 1.15rem; margin-bottom: 10px; color: #333; }

  /* Form */
  .form-section { background: #fff; border: 1px solid #ddd; border-radius: 8px; padding: 18px; margin-bottom: 20px; }
  .form-row { display: flex; flex-wrap: wrap; gap: 10px; align-items: flex-end; margin-bottom: 10px; }
  .form-group { display: flex; flex-direction: column; }
  .form-group label { font-size: 0.82rem; font-weight: 600; margin-bottom: 3px; color: #555; }
  .form-group input, .form-group select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: 0.95rem; }
  .form-group input:focus, .form-group select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,0.2); }
  #add-expense { padding: 8px 20px; background: #4a90d9; color: #fff; border: none; border-radius: 5px; font-size: 0.95rem; cursor: pointer; font-weight: 600; height: 36px; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #d32f2f; font-size: 0.88rem; min-height: 1.2em; margin-top: 4px; }

  /* Filters */
  .filter-section { background: #fff; border: 1px solid #ddd; border-radius: 8px; padding: 14px 18px; margin-bottom: 20px; }
  .filter-row { display: flex; flex-wrap: wrap; gap: 12px; align-items: flex-end; }
  .filter-row .form-group input, .filter-row .form-group select { padding: 6px 8px; font-size: 0.9rem; }

  /* Summary */
  .summary-section { background: #fff; border: 1px solid #ddd; border-radius: 8px; padding: 14px 18px; margin-bottom: 20px; }
  .summary-row { display: flex; flex-wrap: wrap; gap: 14px; align-items: center; }
  .total-box { font-size: 1.1rem; font-weight: 700; color: #2e7d32; }
  .cat-totals { display: flex; flex-wrap: wrap; gap: 10px; }
  .cat-total { background: #e8f0fe; padding: 4px 12px; border-radius: 12px; font-size: 0.85rem; font-weight: 600; color: #1565c0; }

  /* Expense list */
  .expense-list { background: #fff; border: 1px solid #ddd; border-radius: 8px; overflow: hidden; }
  .expense { display: flex; align-items: center; justify-content: space-between; padding: 12px 18px; border-bottom: 1px solid #eee; }
  .expense:last-child { border-bottom: none; }
  .expense-info { display: flex; flex-wrap: wrap; gap: 14px; align-items: center; }
  .expense-amount { font-weight: 700; color: #c62828; font-size: 1rem; min-width: 70px; }
  .expense-cat { background: #f5f5f5; padding: 2px 10px; border-radius: 10px; font-size: 0.82rem; font-weight: 600; text-transform: capitalize; }
  .expense-date { font-size: 0.85rem; color: #777; }
  .expense-note { font-size: 0.82rem; color: #999; font-style: italic; }
  .exp-del { background: none; border: 1px solid #e0e0e0; border-radius: 5px; padding: 4px 10px; cursor: pointer; font-size: 0.82rem; color: #999; }
  .exp-del:hover { color: #d32f2f; border-color: #d32f2f; }

  .empty-msg { padding: 30px; text-align: center; color: #999; font-size: 0.95rem; }
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<!-- Entry Form -->
<div class="form-section">
  <div class="form-row">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" min="0" step="0.01" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shopping">
    </div>
    <button id="add-expense">Add Expense</button>
  </div>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filter-section">
  <h2>Filters</h2>
  <div class="filter-row">
    <div class="form-group">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="form-group">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<!-- Summary -->
<div class="summary-section">
  <div class="summary-row">
    <div class="total-box">Total: <span id="total">0.00</span></div>
    <div class="cat-totals" id="cat-totals"></div>
  </div>
</div>

<!-- Expense List -->
<div class="expense-list" id="expense-list"></div>

<script>
(function() {
  // --- State ---
  var STORAGE_KEY = 'expense_tracker_data';
  var expenses = [];

  // --- DOM refs ---
  var amountInput = document.getElementById('amount');
  var categorySelect = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var addBtn = document.getElementById('add-expense');
  var formError = document.getElementById('form-error');
  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');
  var totalEl = document.getElementById('total');
  var catTotalsEl = document.getElementById('cat-totals');
  var expenseListEl = document.getElementById('expense-list');

  // --- Helpers ---
  function generateId() {
    return Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
  }

  function formatCurrency(num) {
    return num.toFixed(2);
  }

  function saveToStorage() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch(e) { /* ignore quota errors */ }
  }

  function loadFromStorage() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        expenses = JSON.parse(raw);
      }
    } catch(e) {
      expenses = [];
    }
  }

  // --- Validation ---
  function validate() {
    var val = amountInput.value.trim();
    var dateVal = dateInput.value.trim();

    if (val === '' || dateVal === '') {
      formError.textContent = 'Please enter both an amount and a date.';
      return false;
    }

    var num = parseFloat(val);
    if (isNaN(num) || num <= 0) {
      formError.textContent = 'Amount must be a positive number.';
      return false;
    }

    formError.textContent = '';
    return true;
  }

  // --- Add Expense ---
  function addExpense() {
    if (!validate()) return;

    var expense = {
      id: generateId(),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value,
      note: noteInput.value.trim(),
      createdAt: Date.now()
    };

    expenses.push(expense);
    saveToStorage();

    // Reset amount field and clear error
    amountInput.value = '';
    formError.textContent = '';

    render();
  }

  // --- Delete Expense ---
  function deleteExpense(id) {
    expenses = expenses.filter(function(e) { return e.id !== id; });
    saveToStorage();
    render();
  }

  // --- Filtering ---
  function getFilteredExpenses() {
    var catFilter = filterCategory.value;
    var fromFilter = filterFrom.value;
    var toFilter = filterTo.value;

    return expenses.filter(function(e) {
      // Category filter
      if (catFilter !== 'all' && e.category !== catFilter) return false;

      // Date range filter
      if (fromFilter && e.date < fromFilter) return false;
      if (toFilter && e.date > toFilter) return false;

      return true;
    });
  }

  // --- Render ---
  function render() {
    var filtered = getFilteredExpenses();

    // Sort newest first
    filtered.sort(function(a, b) {
      if (b.createdAt !== a.createdAt) return b.createdAt - a.createdAt;
      return b.date.localeCompare(a.date);
    });

    // Total
    var total = filtered.reduce(function(sum, e) { return sum + e.amount; }, 0);
    totalEl.textContent = formatCurrency(total);

    // Category totals
    var catMap = {};
    var categories = ['groceries', 'transport', 'bills', 'fun'];
    categories.forEach(function(c) { catMap[c] = 0; });
    filtered.forEach(function(e) {
      if (catMap.hasOwnProperty(e.category)) {
        catMap[e.category] += e.amount;
      }
    });

    catTotalsEl.innerHTML = '';
    categories.forEach(function(c) {
      if (catMap[c] > 0) {
        var div = document.createElement('div');
        div.className = 'cat-total';
        div.setAttribute('data-cat', c);
        div.textContent = c + ': ' + formatCurrency(catMap[c]);
        catTotalsEl.appendChild(div);
      }
    });

    // Expense list
    expenseListEl.innerHTML = '';
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<div class="empty-msg">No expenses to display.</div>';
      return;
    }

    filtered.forEach(function(e) {
      var row = document.createElement('div');
      row.className = 'expense';

      var info = document.createElement('div');
      info.className = 'expense-info';

      var amountSpan = document.createElement('span');
      amountSpan.className = 'expense-amount';
      amountSpan.textContent = formatCurrency(e.amount);

      var catSpan = document.createElement('span');
      catSpan.className = 'expense-cat';
      catSpan.textContent = e.category;

      var dateSpan = document.createElement('span');
      dateSpan.className = 'expense-date';
      dateSpan.textContent = e.date;

      info.appendChild(amountSpan);
      info.appendChild(catSpan);
      info.appendChild(dateSpan);

      if (e.note) {
        var noteSpan = document.createElement('span');
        noteSpan.className = 'expense-note';
        noteSpan.textContent = e.note;
        info.appendChild(noteSpan);
      }

      var delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.addEventListener('click', function() {
        deleteExpense(e.id);
      });

      row.appendChild(info);
      row.appendChild(delBtn);
      expenseListEl.appendChild(row);
    });
  }

  // --- Event Listeners ---
  addBtn.addEventListener('click', addExpense);

  // Allow Enter key in amount field to submit
  amountInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      e.preventDefault();
      addExpense();
    }
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // --- Init ---
  loadFromStorage();

  // Set default date to today
  var today = new Date();
  var yyyy = today.getFullYear();
  var mm = String(today.getMonth() + 1).padStart(2, '0');
  var dd = String(today.getDate()).padStart(2, '0');
  dateInput.value = yyyy + '-' + mm + '-' + dd;

  render();
})();
</script>

</body>
</html>
